/**
 * A menu item that can be toggled between checked and unchecked states.
 *
 * ### Component Props
 *
 * See [Context Menu props](https://www.radix-ui.com/primitives/docs/components/context-menu) documentation for full details.
 *
 * | Prop                | Type                                          | Default |
 * | :------------------ | :-------------------------------------------- | :------ |
 * | _asChild_           | `boolean`                                     | `false` |
 * | _checked_           | `boolean \| "indeterminate"`                  | -       |
 * | _onCheckedChange_   | `(checked: boolean) => void`                  | -       |
 * | _disabled_          | `boolean`                                     | -       |
 * | _onSelect_          | `(event: Event) => void`                      | -       |
 * | _textValue_         | `string`                                      | -       |
 */
function ContextMenuCheckboxItem({
  className,
  children,
  checked,
  ...props
}: React.ComponentProps<typeof ContextMenuPrimitive.CheckboxItem>) {
  return (
    <ContextMenuPrimitive.CheckboxItem
      data-slot="context-menu-checkbox-item"
      className={cn(
        "relative flex cursor-default items-center gap-2 rounded py-1.5 pr-8 pl-2 text-sm outline-hidden select-none focus:bg-accent focus:text-accent-foreground focus:ring-1 focus:ring-ring focus:ring-inset data-disabled:pointer-events-none data-disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4",
        className
      )}
      checked={checked}
      {...props}
    >
      <span className="pointer-events-none absolute right-2">
        <ContextMenuPrimitive.ItemIndicator>
          <Check />
        </ContextMenuPrimitive.ItemIndicator>
      </span>
      {children}
    </ContextMenuPrimitive.CheckboxItem>
  );
}

